export const 祈雲符 = (bi) => {
    const u = bi.u, k = 2.55;
    const X = (c) => (c - 3.6) * k;
    const Z = (r) => (r - 5.0) * k + 1.0;
    const 線 = (書, 寬 = 0.62) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.65) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    const 點 = (x, z, r = 0.42) => bi.塊(p => p.M(X(x - r), Z(z)).C(X(x - r), Z(z - r * 1.3), X(x + r), Z(z - r * 1.3), X(x + r), Z(z))
        .C(X(x + r), Z(z + r * 1.3), X(x - r), Z(z + r * 1.3), X(x - r), Z(z)).close());
    // 雨冠
    線(p => p.M(X(0.15), Z(5.65)).L(X(6.9), Z(5.58)), 0.8);
    出(p => p.M(X(0.35), Z(5.70)).L(X(0.33), Z(19.41)).C(X(0.32), Z(19.95), X(0.22), Z(20.35), X(0.08), Z(20.62)), 0.7);
    出(p => p.M(X(6.85), Z(5.70)).L(X(6.83), Z(18.46)).C(X(6.85), Z(19.00), X(6.95), Z(19.41), X(7.1), Z(19.68)), 0.7);
    線(p => p.M(X(0.8), Z(6.50)).L(X(2.4), Z(6.46)), 0.55);
    線(p => p.M(X(0.8), Z(7.10)).L(X(2.4), Z(7.06)), 0.55);
    線(p => p.M(X(0.8), Z(7.70)).L(X(2.4), Z(7.66)), 0.55);
    線(p => p.M(X(3.45), Z(5.75)).L(X(3.43), Z(8.30)), 0.6);
    // 右欠曲
    出(p => p.M(X(4.6), Z(6.20)).C(X(4.1), Z(6.70), X(3.9), Z(7.20), X(4.3), Z(7.50)), 0.6);
    出(p => p.M(X(4.7), Z(6.30)).C(X(5.2), Z(7.00), X(5.4), Z(7.70), X(5.6), Z(8.20)), 0.6);
    // 左王形
    線(p => p.M(X(0.7), Z(9.01)).L(X(2.2), Z(8.96)), 0.55);
    線(p => p.M(X(0.7), Z(10.22)).L(X(2.2), Z(10.17)), 0.55);
    線(p => p.M(X(0.7), Z(11.44)).L(X(2.2), Z(11.39)), 0.55);
    線(p => p.M(X(1.45), Z(9.01)).L(X(1.43), Z(11.44)), 0.55);
    // 大用框（內桁三中豎）
    線(p => p.M(X(1.5), Z(11.85)).L(X(1.5), Z(19.41)).L(X(6.3), Z(19.32)).L(X(6.3), Z(11.76)).L(X(1.45), Z(11.85)), 0.6);
    線(p => p.M(X(1.6), Z(13.74)).L(X(6.2), Z(13.68)), 0.5);
    線(p => p.M(X(1.6), Z(15.62)).L(X(6.2), Z(15.57)), 0.5);
    線(p => p.M(X(1.6), Z(17.52)).L(X(6.2), Z(17.46)), 0.5);
    線(p => p.M(X(3.9), Z(11.91)).L(X(3.88), Z(19.27)), 0.55);
    // 乙鉤承中垂
    線(p => p.M(X(3.0), Z(19.95)).C(X(2.6), Z(20.62), X(2.9), Z(21.30), X(3.5), Z(21.30)).C(X(4.0), Z(21.30), X(4.2), Z(20.76), X(3.9), Z(20.35)), 0.6);
    出(p => p.M(X(3.55), Z(21.43)).L(X(3.53), Z(23.73)), 0.62);
    點(3.55, 24.94);
};
